example.code:
// Full page screenshot
await page.screenshot({
  path: 'fullpage.png',
  fullPage: true
});

// Specific element only
const element = await page.$('#chart');
await element.screenshot({ path: 'chart.png' });

await page.screenshot({
  path: 'screenshot.png',
  type: 'png',       // or 'jpeg', 'webp'
  quality: 80,       // jpeg/webp only
  clip: { x: 0, y: 0, width: 800, height: 600 },
  omitBackground: true // transparent background
});

// As base64 (no path required — useful for passing to APIs)
const base64 = await page.screenshot({ encoding: 'base64' });

await page.pdf({
  path: 'document.pdf',
  format: 'A4',  // or 'Letter', 'Legal', etc.
  printBackground: true,
  margin: { top: '1cm', right: '1cm', bottom: '1cm', left: '1cm' },
  displayHeaderFooter: true,
  headerTemplate: '<div style="font-size:10px;text-align:center;width:100%;">Header</div>',
  footerTemplate: '<div style="font-size:10px;text-align:center;width:100%;"><span class="pageNumber"></span>/<span class="totalPages"></span></div>'
});
